// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//DeepSeek
float zoomFactor = 1.0 + audioLowSmooth * 0.035; // Adjust the multiplier to control the zoom intensity, tweaked by me
vUv = vec2(0.5, 0.5) + (vUvOriginal - vec2(0.5, 0.5)) / zoomFactor;

//ROVASTAR's Kaleidoscope Code, mashed up with Krash's movement code.

    float rad_lq = vRadius * length(uTexSize.xy)*0.5;
    float ang_lq = vAngle;
    vec2 uv_temp1 = (vUv - 0.5) * uTexSize.xy;
    float rad_hq = length(uv_temp1);
    float ang_hq = atan(-uv_temp1.y, uv_temp1.x);

    vec2 uv_kal = (vUv - 0.5);
    float rad2 = rad_hq*0.8;
    float ang2 = ang_hq * M_INV_PI_2;

        // ROTATION OVER TIME
        #if 1
          ang2 -= q11/7.5;   //rotate over uTime
        #endif

        // FIN TYPE
        //float fins = 1 + floor(rand_preset.z*5.95);
        float fins = q9 + floor(rand_preset.z*2.95);

        #if 1     // SHARP FINS
          ang2 = fract(ang2*fins)/fins;
              // ENABLE THIS TO MAKE THE FINS ALTERNATE: (seamless!)
              ang2 = abs(ang2 - 0.5/fins);
        #else     // COSINE FINS - a bit slow
          ang2 = cos(ang2*M_PI_2*fins) * 0.023;
        #endif

        // RADIAL KALEIDOSCOPING?
        #if 0
          rad2 *= g_fTexSize.z;
            // choose one:
            //rad2 = mix(rad2, fract(rad2*3)/3.0, 0.6);
            rad2 = cos(rad2*5);
            //rad2 = sqrt(rad2)*0.5;
            //rad2 += abs(fract(rad2*7)-0.5)/7.0 * 1.15;  // stepifier
            //rad2 += cos(rad2*61)*0.02;
          rad2 *= g_fTexSize.x;
        #endif

    ang2 *= M_PI_2;
    uv_out = 0.25 + rad2*vec2(cos(ang2),sin(ang2))*uTexSize.zw;
    uv_out.y = 1.1-uv_out.y;

    ret = texture(sampler_main, uv_out).xyz;

    vec2 reference_size = vec2(1920, 1080)*14.275; // Fixed reference size (popular resolution is 1920x1080) and patched the aprox. 1080px image resolution by multiplying.

    if (q3 == 0)
    {
       uv_scaled = vec2(uv_out.x-.5,uv_out.y-1)/5.35 * reference_size * texsize_ibtS_spr_dance_0.zw + vec2 (0.5, q7);
       uv_scaled += vec2(.1925, 0); //Position fix
       uv_scaled *= (uv_scaled.x>0) * (uv_scaled.y>0) * (uv_scaled.x<1) * (uv_scaled.y<1);
       uv_scaled = clamp(uv_scaled, 0.0, 1.0); // Proper UV clamping
       float edgeFade = EdgeFade(uv_scaled, 0.01); // 1% margin fading

       //Se7enSlasher - Using my black background removal technique because it doesn't support transparency on any image files on MilkDrop. So I have implemented instead.
       float AbbieDance1_Lum = lum(texture(AbbieDance1, uv_scaled) * edgeFade);

       if (AbbieDance1_Lum > .2)
       { ret = texture(AbbieDance1, uv_scaled);  }
    }

    if (q3 == 1)
    {
       uv_scaled = vec2(uv_out.x-.5,uv_out.y-1)/5.35 * reference_size * texsize_ibtS_spr_dance_1.zw + vec2 (0.5, q7);
       uv_scaled += vec2(.245, 0); //Position fix
       uv_scaled *= (uv_scaled.x>0) * (uv_scaled.y>0) * (uv_scaled.x<1) * (uv_scaled.y<1);
       uv_scaled = clamp(uv_scaled, 0.0, 1.0); // Proper UV clamping
       float edgeFade = EdgeFade(uv_scaled, 0.01); // 1% margin fading

       float AbbieDance2_Lum = lum(texture(AbbieDance2, uv_scaled) * edgeFade);

       if (AbbieDance2_Lum > .2)
       { ret = texture(AbbieDance2, uv_scaled);  }
    }

    if (q3 == 2)
    {
       uv_scaled = vec2(uv_out.x-.5,uv_out.y-1)/5.35 * reference_size * texsize_ibtS_spr_dance_2.zw + vec2 (0.5, q7);
       uv_scaled += vec2(-.19325, 0); //Position fix
       uv_scaled *= (uv_scaled.x>0) * (uv_scaled.y>0) * (uv_scaled.x<1) * (uv_scaled.y<1);
       uv_scaled = clamp(uv_scaled, 0.0, 1.0); // Proper UV clamping
       float edgeFade = EdgeFade(uv_scaled, 0.01); // 1% margin fading

       float AbbieDance3_Lum = lum(texture(AbbieDance3, uv_scaled) * edgeFade);

       if (AbbieDance3_Lum > .2)
       { ret = texture(AbbieDance3, uv_scaled);  }
    }

    if (q3 == 3)
    {
       uv_scaled = vec2(uv_out.x-.5,uv_out.y-1)/5.35 * reference_size * texsize_ibtS_spr_dance_3.zw + vec2 (0.5, q7);
       uv_scaled += vec2(-.26, 0); //Position fix
       uv_scaled *= (uv_scaled.x>0) * (uv_scaled.y>0) * (uv_scaled.x<1) * (uv_scaled.y<1);
       uv_scaled = clamp(uv_scaled, 0.0, 1.0); // Proper UV clamping
       float edgeFade = EdgeFade(uv_scaled, 0.01); // 1% margin fading

       float AbbieDance4_Lum = lum(texture(AbbieDance4, uv_scaled) * edgeFade);

       if (AbbieDance4_Lum > .2)
       { ret = texture(AbbieDance4, uv_scaled);  }
    }

      //Claude AI's Heart Code
    // Heart shape using standard mathematical formula
  vec2 uv2 = vUv - 0.5;
  uv2.x *= uTexSize.x/uTexSize.y;  // correct uAspect ratio

  // Scale and flip the coordinates
  uv2.y = -uv2.y;
  uv2 *= 2.5;

  // Standard heart formula
  vec2 q = vec2(uv2.x, uv2.y - sqrt(abs(uv2.x))*0.5) + vec2 (0, .125);
  float d = length(q) - 0.5 + 0.15*(-q6*2);

  // Create a soft glow effect
  float glow = 0.05/abs(d);
  glow = clamp01(glow);

  // Add the heart with color
  vec3 heartColor = vec3(0.8, 0.1, 0.3);  // red heart
  heartColor *= 1.0 + .5*q6;  // pulsing effect

  // Combine everything
  vec3 uv_heart = glow * heartColor*3; //Declare a new heart composition layer.
  //ret = uv_out;
  ret += uv_heart * q7;


  fragColor = ret;
}
